namespace sv_8fd80dfc04794f83afccea947286027a.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable view models for form binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime StartDate { get; set; } = DateTime.Today;
    public DateTime? EndDate { get; set; } = DateTime.Today;
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

using sv_8fd80dfc04794f83afccea947286027a.Models;

namespace sv_8fd80dfc04794f83afccea947286027a.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(500); // Simulate network call
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(200); // Simulate validation
        return !string.IsNullOrWhiteSpace(email)
            && email.Contains('@')
            && email.Contains('.');
    }
}

@namespace sv_8fd80dfc04794f83afccea947286027a.Components.Apply

<nav aria-label="Application progress" class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isActive = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isActive && !isCompleted;

            <li class="text-center flex-fill position-relative @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0 w-100" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle bg-success text-white">&#10003;</span>
                        <span class="d-block small mt-1 text-success fw-semibold">@StepNames[i]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(isActive ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">@step</span>
                        <span class="d-block small mt-1 @(isActive ? "text-primary fw-semibold" : "text-muted")">@StepNames[i]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

<style>
    .step-indicator .step-circle {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 36px;
        height: 36px;
        border-radius: 50%;
        font-weight: bold;
        font-size: 0.9rem;
    }
</style>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };
}

@namespace sv_8fd80dfc04794f83afccea947286027a.Components.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
