@namespace sv_8fd80dfc04794f83afccea947286027a.Components.Apply

<nav aria-label="Application progress" class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isActive = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isActive && !isCompleted;

            <li class="text-center flex-fill position-relative @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0 w-100" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle bg-success text-white">&#10003;</span>
